    for (const [id, track] of Object.entries(characterTracking)) {
      console.log(
        `${id}: seenWalking=${track.seenWalking}, frameChanges=${track.frameChanges}, ` +
        `maxStuckCount=${track.stuckCount}`
      );
    }

    // If any character was observed walking, their frames must have changed
    const walkers = Object.entries(characterTracking).filter(([, t]) => t.seenWalking);

