      // (that would mean 1.5s+ with no frame advance despite being in 'walking' action)
      expect(track.stuckCount,
        `${id} was stuck on the same walkFrame for ${track.stuckCount} consecutive samples (${track.stuckCount * 500}ms)`
      ).toBeLessThanOrEqual(3);
    }
  });
});

