  // ── TEST 4: Live sim — no stuck walkFrame during walking ──────────────────

  test('walkFrame cycles over time — no character stuck on same frame while walking', async ({ page }) => {
    test.setTimeout(90_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });
    await startEngine(page, 10); // 10x speed to observe more walking activity

    // Observe walk states every 500ms for 30 real seconds (= 300 sim seconds at 10x)
    const OBSERVE_MS = 30_000;
    const SAMPLE_INTERVAL_MS = 500;
    const deadline = Date.now() + OBSERVE_MS;

    // Track per-character: {lastWalkFrame, stuckSamples, cycledFrames, seenWalking}
    const characterTracking = {};

    let totalSamples = 0;
    let walkingSamples = 0;

    while (Date.now() < deadline) {
      const states = await getWalkStates(page);
      totalSamples++;

      for (const c of states) {
        if (!characterTracking[c.id]) {
          characterTracking[c.id] = {
            lastWalkFrame: null,
            stuckCount: 0,      // consecutive samples with same walkFrame while walking
            frameChanges: 0,    // times walkFrame changed while walking
            seenWalking: false,
          };
        }

        const track = characterTracking[c.id];

        if (c.action === 'walking') {
          walkingSamples++;
          track.seenWalking = true;

          if (track.lastWalkFrame === null) {
            track.lastWalkFrame = c.walkFrame;
          } else if (c.walkFrame !== track.lastWalkFrame) {
            track.frameChanges++;
            track.stuckCount = 0;
            track.lastWalkFrame = c.walkFrame;
          } else {
            // Same frame — only flag as stuck if same frame for 3+ consecutive samples
            // (3 * 500ms = 1500ms with same frame is a clear freeze; normal cycling is ~200ms)
            track.stuckCount++;
          }
        } else {
          // Reset stuck tracking when not walking (idle/interacting is fine)
          track.lastWalkFrame = null;
          track.stuckCount = 0;
        }
      }

      await page.waitForTimeout(SAMPLE_INTERVAL_MS);
    }

    console.log(`Observed ${totalSamples} total samples, ${walkingSamples} walking-character samples`);
    for (const [id, track] of Object.entries(characterTracking)) {
      console.log(
        `${id}: seenWalking=${track.seenWalking}, frameChanges=${track.frameChanges}, ` +
        `maxStuckCount=${track.stuckCount}`
      );
    }

    // If any character was observed walking, their frames must have changed
    const walkers = Object.entries(characterTracking).filter(([, t]) => t.seenWalking);

    if (walkers.length === 0) {
      // No walking observed in 30s — skip rather than fail (AI may choose idle/interact)
      console.log('[SKIP] No characters observed walking during the 30s observation window');
      return;
    }

    for (const [id, track] of walkers) {
      // Must have seen at least one frame change (animation is cycling)
      expect(track.frameChanges,
        `${id} was observed walking but walkFrame never changed — animation appears frozen`
      ).toBeGreaterThan(0);

      // At no point should a character be stuck on the same walkFrame for >3 consecutive 500ms samples
      // (that would mean 1.5s+ with no frame advance despite being in 'walking' action)
      expect(track.stuckCount,
        `${id} was stuck on the same walkFrame for ${track.stuckCount} consecutive samples (${track.stuckCount * 500}ms)`
      ).toBeLessThanOrEqual(3);
    }
  });
});

